namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(new[]
        {
            CreateNotification("Welcome to the notification center!"),
            CreateNotification("Your profile was updated successfully."),
            CreateNotification("New comment on your post."),
        });
    }

    /// <summary>Returns all notifications.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>Returns only notifications newer than the given timestamp.</summary>
    public List<Notification> GetSince(DateTime since)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Timestamp > since).ToList();
        }
    }

    /// <summary>
    /// Simulates an external system occasionally producing notifications.
    /// Called by a background service so the polling page has something to find.
    /// </summary>
    public void AddRandom()
    {
        string[] templates =
        [
            "Server CPU usage is at {0}%",
            "Deployment #{0} completed",
            "User #{0} signed up",
            "Backup #{0} finished",
            "Alert: disk usage above {0}%",
        ];

        var msg = string.Format(
            templates[Random.Shared.Next(templates.Length)],
            Random.Shared.Next(1, 100));

        lock (_lock)
        {
            _notifications.Add(CreateNotification(msg));
        }
    }

    private Notification CreateNotification(string message)
        => new(Interlocked.Increment(ref _nextId), message, DateTime.UtcNow);
}

namespace BlazorNotifications.Services;

/// <summary>
/// Background hosted service that periodically adds fake notifications
/// so the polling page has new data to discover.
/// </summary>
public class NotificationProducerService(NotificationService notifications) : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(8), stoppingToken);
            notifications.AddRandom();
        }
    }
}

@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@implements IDisposable
@inject BlazorNotifications.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group mt-3">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<BlazorNotifications.Services.Notification> notifications = new();
    private CancellationTokenSource? _cts;

    // Runs during prerender AND when the page becomes interactive.
    // The first call populates the list for SSR; the second call
    // sees the same snapshot (already assigned) and skips re-fetching.
    protected override void OnInitialized()
    {
        if (notifications.Count == 0)
        {
            notifications = NotificationService.GetAll();
        }
    }

    // Called only once after the component is fully interactive in the browser.
    // This is where we start the polling loop — it never fires during prerender.
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var latest = notifications.Count > 0
                ? notifications.Max(n => n.Timestamp)
                : DateTime.MinValue;

            var newer = NotificationService.GetSince(latest);

            if (newer.Count > 0)
            {
                notifications.AddRange(newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

