+        _notifications.AddRange(new[]
+        {
+            CreateNotification("Welcome to the notification center!"),
+            CreateNotification("Your profile was updated successfully."),
+            CreateNotification("New comment on your post."),
+        });
+    }
+
+    /// <summary>Returns all notifications.</summary>
+    public List<Notification> GetAll()
+    {
+        lock (_lock)
+        {
+            return _notifications.ToList();
+        }
+    }
+
+    /// <summary>Returns only notifications newer than the given timestamp.</summary>
+    public List<Notification> GetSince(DateTime since)
+    {
+        lock (_lock)
+        {
+            return _notifications.Where(n => n.Timestamp > since).ToList();
+        }
+    }
+
+    /// <summary>
+    /// Simulates an external system occasionally producing notifications.
+    /// Called by a background service so the polling page has something to find.
+    /// </summary>
+    public void AddRandom()
+    {
+        string[] templates =
+        [
+            "Server CPU usage is at {0}%",
+            "Deployment #{0} completed",
+            "User #{0} signed up",
+            "Backup #{0} finished",
+            "Alert: disk usage above {0}%",
+        ];
+
+        var msg = string.Format(
+            templates[Random.Shared.Next(templates.Length)],
+            Random.Shared.Next(1, 100));
+
+        lock (_lock)
+        {
+            _notifications.Add(CreateNotification(msg));
+        }
+    }
+
+    private Notification CreateNotification(string message)
+        => new(Interlocked.Increment(ref _nextId), message, DateTime.UtcNow);
+}
